@Test
void testSideOutputLateDataForMergingWindowsWithWindowRetirement() throws Exception {
    // Test for bug where elements assigned to windows that become late due to merging
    // are not side-output as late data when they should be.
    //
    // Scenario:
    // - Session windows with gap=100ms, allowedLateness=0
    // - Element E1 at 1000 creates window [1000, 1100]
    // - Element E2 at 200 creates window [200, 300]
    // - Watermark advances to 400, making window [200, 300] late
    // - Element E3 at 250 should be assigned to [250, 350]:
    //   - Does it merge with [200, 300]? Yes, because 250 is within [200, 300]
    //   - Does it merge with [1000, 1100]? No.
    //   - After merge: [200, 350]
    //   - Is [200, 350] late? Yes, because 350 + 0 <= 400
    //   - Window is retired, E3 is not added
    //   - isSkippedElement = true
    //   - isElementLate(E3) = true (250 + 0 <= 400? yes)
    //   - E3 should be side output!

    final long gapSize = 100; // milliseconds
    final long lateness = 0;

    ReducingStateDescriptor<Tuple2<String, Integer>> stateDesc =
            new ReducingStateDescriptor<>(
                    "window-contents",
                    new SumReducer(),
                    STRING_INT_TUPLE.createSerializer(new SerializerConfigImpl()));

    WindowOperatorFactory<
                    String,
                    Tuple2<String, Integer>,
                    Tuple2<String, Integer>,
                    Tuple3<String, Long, Long>,
                    TimeWindow>
            operator =
                    new WindowOperatorFactory<>(
                            EventTimeSessionWindows.withGap(Duration.ofMillis(gapSize)),
                            new TimeWindow.Serializer(),
                            new TupleKeySelector(),
                            BasicTypeInfo.STRING_TYPE_INFO.createSerializer(
                                    new SerializerConfigImpl()),
                            stateDesc,
                            new InternalSingleValueWindowFunction<>(
                                    new ReducedSessionWindowFunction()),
                            EventTimeTrigger.create(),
                            lateness,
                            lateOutputTag);

    OneInputStreamOperatorTestHarness<Tuple2<String, Integer>, Tuple3<String, Long, Long>>
            testHarness = createTestHarness(operator);

    testHarness.open();

    ConcurrentLinkedQueue<Object> expected = new ConcurrentLinkedQueue<>();
    ConcurrentLinkedQueue<Object> sideExpected = new ConcurrentLinkedQueue<>();

    // First element creates window [200, 300]
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 200));
    testHarness.processWatermark(new Watermark(350));
    expected.add(new Watermark(350));

    // Advance watermark past cleanup time of [200, 300]
    // cleanup = 300 + 0 = 300, watermark = 350, so window is late
    testHarness.processWatermark(new Watermark(400));
    expected.add(new StreamRecord<>(new Tuple3<>("key1-1", 200L, 300L), 299));
    expected.add(new Watermark(400));

    // This element should be side-output as late
    // Window [250, 350] would merge with [200, 300] to [200, 350]
    // [200, 350] is late (350 + 0 <= 400), so it's retired
    // isSkippedElement = true, isElementLate(250) = true (250 + 0 <= 400)
    // Should be side output!
    testHarness.processElement(new StreamRecord<>(new Tuple2<>("key1", 1), 250));
    sideExpected.add(new StreamRecord<>(new Tuple2<>("key1", 1), 250));

    ConcurrentLinkedQueue<Object> actual = testHarness.getOutput();
    ConcurrentLinkedQueue<StreamRecord<Tuple2<String, Integer>>> sideActual =
            testHarness.getSideOutput(lateOutputTag);

    TestHarnessUtil.assertOutputEqualsSorted(
            "Output was not correct.", expected, actual, new Tuple2ResultSortComparator());
    TestHarnessUtil.assertOutputEqualsSorted(
            "SideOutput was not correct.",
            sideExpected,
            (Iterable) sideActual,
            new Tuple2ResultSortComparator());
    testHarness.close();
}

