    @Override
    public OperatorAttributes getOperatorAttributes() {
        boolean isOutputOnlyAfterEndOfStream =
                windowAssigner instanceof GlobalWindows
                        && trigger instanceof GlobalWindows.EndOfStreamTrigger;
